app.post('/login', (req, res) => {
  const { username, password, client_id, redirect_uri, state, scope } = req.body;

  const user = users[username];
  if (!user || user.password !== password) {
    return res.status(401).send('Invalid username or password');
  }

  const client = clients[client_id];
  if (!client) {
    return res.status(400).send('Invalid client_id');
  }

  if (!client.redirect_uris.includes(redirect_uri)) {
    return res.status(400).send('Invalid redirect_uri');
  }

  const authCode = generateRandomString();
  const expiresAt = Date.now() + 600000;

  authorizationCodes.set(authCode, {
    client_id,
    redirect_uri,
    username,
    scope: scope || '',
    expiresAt
  });

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', authCode);
  if (state) {
    redirectUrl.searchParams.append('state', state);
  }

  res.redirect(redirectUrl.toString());
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret, refresh_token } = req.body;

  let authHeader = req.headers.authorization;
  let authClientId = client_id;
  let authClientSecret = client_secret;

  if (authHeader && authHeader.startsWith('Basic ')) {
    const base64Credentials = authHeader.slice(6);
    const credentials = Buffer.from(base64Credentials, 'base64').toString('utf-8');
    const [id, secret] = credentials.split(':');
    authClientId = id;
    authClientSecret = secret;
  }

  const client = clients[authClientId];
  if (!client || client.client_secret !== authClientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (grant_type === 'authorization_code') {
    if (!code || !redirect_uri) {
      return res.status(400).json({ error: 'invalid_request' });
    }

    const authData = authorizationCodes.get(code);
    if (!authData) {
      return res.status(400).json({ error: 'invalid_grant' });
    }

    if (authData.expiresAt < Date.now()) {
      authorizationCodes.delete(code);
      return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code expired' });
    }

    if (authData.client_id !== authClientId || authData.redirect_uri !== redirect_uri) {
      return res.status(400).json({ error: 'invalid_grant' });
    }

    authorizationCodes.delete(code);

    const accessToken = generateRandomString();
    const refreshTokenValue = generateRandomString();
    const expiresIn = 3600;

    accessTokens.set(accessToken, {
      client_id: authClientId,
      username: authData.username,
      scope: authData.scope,
      expiresAt: Date.now() + (expiresIn * 1000)
    });

    refreshTokens.set(refreshTokenValue, {
      client_id: authClientId,
      username: authData.username,
      scope: authData.scope
    });

    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: expiresIn,
      refresh_token: refreshTokenValue,
      scope: authData.scope
    });

  } else if (grant_type === 'refresh_token') {
    if (!refresh_token) {
      return res.status(400).json({ error: 'invalid_request' });
    }

    const refreshData = refreshTokens.get(refresh_token);
    if (!refreshData || refreshData.client_id !== authClientId) {
      return res.status(400).json({ error: 'invalid_grant' });
    }

    const accessToken = generateRandomString();
    const expiresIn = 3600;

    accessTokens.set(accessToken, {
      client_id: authClientId,
      username: refreshData.username,
      scope: refreshData.scope,
      expiresAt: Date.now() + (expiresIn * 1000)
    });

    return res.json({
      access_token: accessToken,
      token_type: 'Bearer',
      expires_in: expiresIn,
      scope: refreshData.scope
    });

  } else {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  if (tokenData.expiresAt < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'invalid_token', error_description: 'Token expired' });
  }

  const user = users[tokenData.username];
  if (!user) {
    return res.status(404).json({ error: 'user_not_found' });
  }

  return res.json({
    sub: tokenData.username,
    username: user.username,
    email: user.email
  });
});

app.post('/revoke', (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  if (token_type_hint === 'access_token' || !token_type_hint) {
    accessTokens.delete(token);
  }

  if (token_type_hint === 'refresh_token' || !token_type_hint) {
    refreshTokens.delete(token);
  }

  return res.status(200).send();
});

app.get('/.well-known/oauth-authorization-server', (req, res) => {
  const baseUrl = `${req.protocol}://${req.get('host')}`;
  res.json({
    issuer: baseUrl,
    authorization_endpoint: `${baseUrl}/authorize`,
    token_endpoint: `${baseUrl}/token`,
    userinfo_endpoint: `${baseUrl}/userinfo`,
    revocation_endpoint: `${baseUrl}/revoke`,
    response_types_supported: ['code'],
    grant_types_supported: ['authorization_code', 'refresh_token'],
    token_endpoint_auth_methods_supported: ['client_secret_basic', 'client_secret_post']
  });
});

